private String persistedContentEncoding(String contentEncoding) {
    if (contentEncoding == null || contentEncoding.isBlank()) {
        return null;
    }
    StringBuilder persisted = new StringBuilder();
    for (String value : contentEncoding.split(",")) {
        String encoding = value.trim();
        if (encoding.isEmpty() || "aws-chunked".equalsIgnoreCase(encoding)) {
            continue;
        }
        if (!persisted.isEmpty()) {
            persisted.append(',');
        }
        persisted.append(encoding);
    }
    return persisted.isEmpty() ? null : persisted.toString();
}

