            }

            int max = (maxKeys != null && maxKeys > 0) ? maxKeys : 1000;
            List<S3Object> objects = s3Service.listObjects(bucket, prefix, delimiter, max);
            boolean v2 = "2".equals(listType);

            XmlBuilder xml = new XmlBuilder()
